        "dialogueHtml": "<span class=\"speaker-text\"><ruby>テ<rt>て</rt></ruby><ruby>ス<rt>す</rt></ruby><ruby>ト<rt>と</rt></ruby><span class=\"keyword\" onclick=\"showTooltip(event, 'に：\\n并列助词。接在名词后，表示事物的罗列和累加。意思是“……加上……”、“又是……又是……”。')\"><ruby>に</rt></ruby><ruby>レ<rt>れ</rt></ruby><ruby>ポ<rt>ぽ</rt></ruby><ruby>ー<rt>ー</rt></ruby><ruby>ト<rt>と</rt></ruby><span class=\"keyword\" onclick=\"showTooltip(event, 'に：\\n同上，表示罗列。')\"><ruby>に</rt></ruby><ruby>来<rt>らい</rt></ruby><ruby>週<rt>しゅう</rt></ruby>の<ruby>発<rt>はっ</rt></ruby><ruby>表<rt>ぴょう</rt></ruby>って、こう<span class=\"keyword\" onclick=\"showTooltip(event, '重なる：\\n动词。指事情或时间集中发生在一起。意思是“重叠”、“赶在一起”。')\"><ruby>重<rt>かさ</rt></ruby>なると</span><span class=\"keyword\" onclick=\"showTooltip(event, 'お手上げ：\\n名词。比喻面对困难毫无办法、就像举起双手投降一样的状态。意思是“束手无策”、“没辙”。')\"><ruby>お<rt>お</rt></ruby><ruby>手<rt>て</rt></ruby>あげ</span>。</span>",
